window.BIBLE["Joel"] = {"1":{"chapter":"1","title":"THE LOCUST PLAGUE","verses":{"1":{"text":"The word of the LORD that came to Joel the son of Pethuel.","ref":"Joel 1:1","synthesized":"This is the word of the LORD that came to Joel son of Pethuel:","sources":{"KJV":{"text":"The word of the LORD that came to Joel the son of Pethuel."},"BSB":{"text":"This is the word of the LORD that came to Joel son of Pethuel:"}},"definableWords":["word","LORD","son"],"peopleInVerse":[]},"2":{"text":"Hear this, ye old men, and give ear, all ye inhabitants of the land. Hath this been in your days, or even in the days of your fathers?","ref":"Joel 1:2","synthesized":"Hear this, O elders; and give ear, all who dwell in the land. Has anything like this ever happened in your days or in the days of your fathers?","sources":{"KJV":{"text":"Hear this, ye old men, and give ear, all ye inhabitants of the land. Hath this been in your days, or even in the days of your fathers?"},"BSB":{"text":"Hear this, O elders; and give ear, all who dwell in the land. Has anything like this ever happened in your days or in the days of your fathers?"}},"definableWords":["hear","land","days","or","fathers"],"peopleInVerse":[]},"3":{"text":"Tell ye your children of it, and let your children tell their children, and their children another generation.","ref":"Joel 1:3","synthesized":"Tell it to your children; let your children tell it to their children, and their children to the next generation.","sources":{"KJV":{"text":"Tell ye your children of it, and let your children tell their children, and their children another generation."},"BSB":{"text":"Tell it to your children; let your children tell it to their children, and their children to the next generation."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"That which the palmerworm hath left hath the locust eaten; and that which the locust hath left hath the cankerworm eaten; and that which the cankerworm hath left hath the caterpiller eaten.","ref":"Joel 1:4","synthesized":"What the devouring locust has left, the swarming locust has eaten; what the swarming locust has left, the young locust has eaten; and what the young locust has left, the destroying locust has eaten.","sources":{"KJV":{"text":"That which the palmerworm hath left hath the locust eaten; and that which the locust hath left hath the cankerworm eaten; and that which the cankerworm hath left hath the caterpiller eaten."},"BSB":{"text":"What the devouring locust has left, the swarming locust has eaten; what the swarming locust has left, the young locust has eaten; and what the young locust has left, the destroying locust has eaten."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Awake, ye drunkards, and weep; and howl, all ye drinkers of wine, because of the new wine; for it is cut off from your mouth.","ref":"Joel 1:5","synthesized":"Wake up, you drunkards, and weep; wail, all you drinkers of wine, because of the sweet wine, for it has been cut off from your mouth.","sources":{"KJV":{"text":"Awake, ye drunkards, and weep; and howl, all ye drinkers of wine, because of the new wine; for it is cut off from your mouth."},"BSB":{"text":"Wake up, you drunkards, and weep; wail, all you drinkers of wine, because of the sweet wine, for it has been cut off from your mouth."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"For a nation is come up upon my land, strong, and without number, whose teeth are the teeth of a lion, and he hath the cheek teeth of a great lion.","ref":"Joel 1:6","synthesized":"For a nation has invaded My land, powerful and without number; its teeth are the teeth of a lion, and its fangs are the fangs of a lioness.","sources":{"KJV":{"text":"For a nation is come up upon my land, strong, and without number, whose teeth are the teeth of a lion, and he hath the cheek teeth of a great lion."},"BSB":{"text":"For a nation has invaded My land, powerful and without number; its teeth are the teeth of a lion, and its fangs are the fangs of a lioness."}},"definableWords":["nation","land","lion"],"peopleInVerse":[]},"7":{"text":"He hath laid my vine waste, and barked my fig tree: he hath made it clean bare, and cast it away; the branches thereof are made white.","ref":"Joel 1:7","synthesized":"It has laid waste My grapevine and splintered My fig tree. It has stripped off the bark and thrown it away; the branches have turned white.","sources":{"KJV":{"text":"He hath laid my vine waste, and barked my fig tree: he hath made it clean bare, and cast it away; the branches thereof are made white."},"BSB":{"text":"It has laid waste My grapevine and splintered My fig tree. It has stripped off the bark and thrown it away; the branches have turned white."}},"definableWords":["tree"],"peopleInVerse":[]},"8":{"text":"Lament like a virgin girded with sackcloth for the husband of her youth.","ref":"Joel 1:8","synthesized":"Wail like a virgin dressed in sackcloth, grieving for the husband of her youth.","sources":{"KJV":{"text":"Lament like a virgin girded with sackcloth for the husband of her youth."},"BSB":{"text":"Wail like a virgin dressed in sackcloth, grieving for the husband of her youth."}},"definableWords":["husband"],"peopleInVerse":[]},"9":{"text":"The meat offering and the drink offering is cut off from the house of the LORD; the priests, the LORD’s ministers, mourn.","ref":"Joel 1:9","synthesized":"Grain and drink offerings have been cut off from the house of the LORD; the priests are in mourning, those who minister before the LORD.","sources":{"KJV":{"text":"The meat offering and the drink offering is cut off from the house of the LORD; the priests, the LORD’s ministers, mourn."},"BSB":{"text":"Grain and drink offerings have been cut off from the house of the LORD; the priests are in mourning, those who minister before the LORD."}},"definableWords":["house","LORD","Lord"],"peopleInVerse":[]},"10":{"text":"The field is wasted, the land mourneth; for the corn is wasted: the new wine is dried up, the oil languisheth.","ref":"Joel 1:10","synthesized":"The field is ruined; the land mourns. For the grain is destroyed, the new wine is dried up, and the oil fails.","sources":{"KJV":{"text":"The field is wasted, the land mourneth; for the corn is wasted: the new wine is dried up, the oil languisheth."},"BSB":{"text":"The field is ruined; the land mourns. For the grain is destroyed, the new wine is dried up, and the oil fails."}},"definableWords":["field","land"],"peopleInVerse":[]},"11":{"text":"Be ye ashamed, O ye husbandmen; howl, O ye vinedressers, for the wheat and for the barley; because the harvest of the field is perished.","ref":"Joel 1:11","synthesized":"Be dismayed, O farmers, wail, O vinedressers, over the wheat and barley, because the harvest of the field has perished.","sources":{"KJV":{"text":"Be ye ashamed, O ye husbandmen; howl, O ye vinedressers, for the wheat and for the barley; because the harvest of the field is perished."},"BSB":{"text":"Be dismayed, O farmers, wail, O vinedressers, over the wheat and barley, because the harvest of the field has perished."}},"definableWords":["field"],"peopleInVerse":[]},"12":{"text":"The vine is dried up, and the fig tree languisheth; the pomegranate tree, the palm tree also, and the apple tree, even all the trees of the field, are withered: because joy is withered away from the sons of men.","ref":"Joel 1:12","synthesized":"The grapevine is dried up, and the fig tree is withered; the pomegranate, palm, and apple— all the trees of the orchard—are withered. Surely the joy of mankind has dried up.","sources":{"KJV":{"text":"The vine is dried up, and the fig tree languisheth; the pomegranate tree, the palm tree also, and the apple tree, even all the trees of the field, are withered: because joy is withered away from the sons of men."},"BSB":{"text":"The grapevine is dried up, and the fig tree is withered; the pomegranate, palm, and apple— all the trees of the orchard—are withered. Surely the joy of mankind has dried up."}},"definableWords":["tree","trees","joy"],"peopleInVerse":[]},"13":{"text":"Gird yourselves, and lament, ye priests: howl, ye ministers of the altar: come, lie all night in sackcloth, ye ministers of my God: for the meat offering and the drink offering is withholden from the house of your God.","ref":"Joel 1:13","synthesized":"Put on sackcloth and lament, O priests; wail, O ministers of the altar. Come, spend the night in sackcloth, O ministers of my God, because the grain and drink offerings are withheld from the house of your God.","sources":{"KJV":{"text":"Gird yourselves, and lament, ye priests: howl, ye ministers of the altar: come, lie all night in sackcloth, ye ministers of my God: for the meat offering and the drink offering is withholden from the house of your God."},"BSB":{"text":"Put on sackcloth and lament, O priests; wail, O ministers of the altar. Come, spend the night in sackcloth, O ministers of my God, because the grain and drink offerings are withheld from the house of your God."}},"definableWords":["altar","night","God","house"],"peopleInVerse":[]},"14":{"text":"Sanctify ye a fast, call a solemn assembly, gather the elders and all the inhabitants of the land into the house of the LORD your God, and cry unto the LORD.","ref":"Joel 1:14","synthesized":"Consecrate a fast; proclaim a solemn assembly! Gather the elders and all the residents of the land to the house of the LORD your God, and cry out to the LORD.","sources":{"KJV":{"text":"Sanctify ye a fast, call a solemn assembly, gather the elders and all the inhabitants of the land into the house of the LORD your God, and cry unto the LORD."},"BSB":{"text":"Consecrate a fast; proclaim a solemn assembly! Gather the elders and all the residents of the land to the house of the LORD your God, and cry out to the LORD."}},"definableWords":["consecrate","fast","land","house","LORD","God","Lord"],"peopleInVerse":[]},"15":{"text":"Alas for the day! for the day of the LORD is at hand, and as a destruction from the Almighty shall it come.","ref":"Joel 1:15","synthesized":"Alas for the day! For the Day of the LORD is near, and it will come as destruction from the Almighty.","sources":{"KJV":{"text":"Alas for the day! for the day of the LORD is at hand, and as a destruction from the Almighty shall it come."},"BSB":{"text":"Alas for the day! For the Day of the LORD is near, and it will come as destruction from the Almighty."}},"definableWords":["day","LORD","Almighty"],"peopleInVerse":[]},"16":{"text":"Is not the meat cut off before our eyes, yea, joy and gladness from the house of our God?","ref":"Joel 1:16","synthesized":"Has not the food been cut off before our very eyes— joy and gladness from the house of our God?","sources":{"KJV":{"text":"Is not the meat cut off before our eyes, yea, joy and gladness from the house of our God?"},"BSB":{"text":"Has not the food been cut off before our very eyes— joy and gladness from the house of our God?"}},"definableWords":["joy","house","God"],"peopleInVerse":[]},"17":{"text":"The seed is rotten under their clods, the garners are laid desolate, the barns are broken down; for the corn is withered.","ref":"Joel 1:17","synthesized":"The seeds lie shriveled beneath the clods; the storehouses are in ruins; the granaries are broken down, for the grain has withered away.","sources":{"KJV":{"text":"The seed is rotten under their clods, the garners are laid desolate, the barns are broken down; for the corn is withered."},"BSB":{"text":"The seeds lie shriveled beneath the clods; the storehouses are in ruins; the granaries are broken down, for the grain has withered away."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"How do the beasts groan! the herds of cattle are perplexed, because they have no pasture; yea, the flocks of sheep are made desolate.","ref":"Joel 1:18","synthesized":"How the cattle groan! The herds wander in confusion because they have no pasture. Even the flocks of sheep are suffering.","sources":{"KJV":{"text":"How do the beasts groan! the herds of cattle are perplexed, because they have no pasture; yea, the flocks of sheep are made desolate."},"BSB":{"text":"How the cattle groan! The herds wander in confusion because they have no pasture. Even the flocks of sheep are suffering."}},"definableWords":["cattle"],"peopleInVerse":[]},"19":{"text":"O LORD, to thee will I cry: for the fire hath devoured the pastures of the wilderness, and the flame hath burned all the trees of the field.","ref":"Joel 1:19","synthesized":"To You, O LORD, I call, for fire has consumed the open pastures and flames have scorched all the trees of the field.","sources":{"KJV":{"text":"O LORD, to thee will I cry: for the fire hath devoured the pastures of the wilderness, and the flame hath burned all the trees of the field."},"BSB":{"text":"To You, O LORD, I call, for fire has consumed the open pastures and flames have scorched all the trees of the field."}},"definableWords":["LORD","trees","field"],"peopleInVerse":[]},"20":{"text":"The beasts of the field cry also unto thee: for the rivers of waters are dried up, and the fire hath devoured the pastures of the wilderness.","ref":"Joel 1:20","synthesized":"Even the beasts of the field pant for You, for the streams of water have dried up, and fire has consumed the open pastures.","sources":{"KJV":{"text":"The beasts of the field cry also unto thee: for the rivers of waters are dried up, and the fire hath devoured the pastures of the wilderness."},"BSB":{"text":"Even the beasts of the field pant for You, for the streams of water have dried up, and fire has consumed the open pastures."}},"definableWords":["field","water"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"POUR OUT MY SPIRIT ON ALL FLESH","verses":{"1":{"text":"Blow ye the trumpet in Zion, and sound an alarm in my holy mountain: let all the inhabitants of the land tremble: for the day of the LORD cometh, for it is nigh at hand;","ref":"Joel 2:1","synthesized":"Blow the ram’s horn in Zion; sound the alarm on My holy mountain! Let all who dwell in the land tremble, for the Day of the LORD is coming; indeed, it is near—","sources":{"KJV":{"text":"Blow ye the trumpet in Zion, and sound an alarm in my holy mountain: let all the inhabitants of the land tremble: for the day of the LORD cometh, for it is nigh at hand;"},"BSB":{"text":"Blow the ram’s horn in Zion; sound the alarm on My holy mountain! Let all who dwell in the land tremble, for the Day of the LORD is coming; indeed, it is near—"}},"definableWords":["Zion","holy","land","day","LORD"],"peopleInVerse":[]},"2":{"text":"A day of darkness and of gloominess, a day of clouds and of thick darkness, as the morning spread upon the mountains: a great people and a strong; there hath not been ever the like, neither shall be any more after it, even to the years of many generations.","ref":"Joel 2:2","synthesized":"a day of darkness and gloom, a day of clouds and blackness. Like the dawn overspreading the mountains a great and strong army appears, such as never was of old, nor will ever be in ages to come.","sources":{"KJV":{"text":"A day of darkness and of gloominess, a day of clouds and of thick darkness, as the morning spread upon the mountains: a great people and a strong; there hath not been ever the like, neither shall be any more after it, even to the years of many generations."},"BSB":{"text":"a day of darkness and gloom, a day of clouds and blackness. Like the dawn overspreading the mountains a great and strong army appears, such as never was of old, nor will ever be in ages to come."}},"definableWords":["day","darkness","great","strong"],"peopleInVerse":[]},"3":{"text":"A fire devoureth before them; and behind them a flame burneth: the land is as the garden of Eden before them, and behind them a desolate wilderness; yea, and nothing shall escape them.","ref":"Joel 2:3","synthesized":"Before them a fire devours, and behind them a flame scorches. The land before them is like the Garden of Eden, but behind them, it is like a desert wasteland— surely nothing will escape them.","sources":{"KJV":{"text":"A fire devoureth before them; and behind them a flame burneth: the land is as the garden of Eden before them, and behind them a desolate wilderness; yea, and nothing shall escape them."},"BSB":{"text":"Before them a fire devours, and behind them a flame scorches. The land before them is like the Garden of Eden, but behind them, it is like a desert wasteland— surely nothing will escape them."}},"definableWords":["land","garden","Eden"],"peopleInVerse":[]},"4":{"text":"The appearance of them is as the appearance of horses; and as horsemen, so shall they run.","ref":"Joel 2:4","synthesized":"Their appearance is like that of horses, and they gallop like swift steeds.","sources":{"KJV":{"text":"The appearance of them is as the appearance of horses; and as horsemen, so shall they run."},"BSB":{"text":"Their appearance is like that of horses, and they gallop like swift steeds."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Like the noise of chariots on the tops of mountains shall they leap, like the noise of a flame of fire that devoureth the stubble, as a strong people set in battle array.","ref":"Joel 2:5","synthesized":"With a sound like that of chariots they bound over the mountaintops, like the crackling of fire consuming stubble, like a mighty army deployed for battle.","sources":{"KJV":{"text":"Like the noise of chariots on the tops of mountains shall they leap, like the noise of a flame of fire that devoureth the stubble, as a strong people set in battle array."},"BSB":{"text":"With a sound like that of chariots they bound over the mountaintops, like the crackling of fire consuming stubble, like a mighty army deployed for battle."}},"definableWords":["mighty"],"peopleInVerse":[]},"6":{"text":"Before their face the people shall be much pained: all faces shall gather blackness.","ref":"Joel 2:6","synthesized":"Nations writhe in horror before them; every face turns pale.","sources":{"KJV":{"text":"Before their face the people shall be much pained: all faces shall gather blackness."},"BSB":{"text":"Nations writhe in horror before them; every face turns pale."}},"definableWords":["nations"],"peopleInVerse":[]},"7":{"text":"They shall run like mighty men; they shall climb the wall like men of war; and they shall march every one on his ways, and they shall not break their ranks:","ref":"Joel 2:7","synthesized":"They charge like mighty men; they scale the walls like men of war. Each one marches in formation, not swerving from the course.","sources":{"KJV":{"text":"They shall run like mighty men; they shall climb the wall like men of war; and they shall march every one on his ways, and they shall not break their ranks:"},"BSB":{"text":"They charge like mighty men; they scale the walls like men of war. Each one marches in formation, not swerving from the course."}},"definableWords":["charge","mighty","men","one"],"peopleInVerse":[]},"8":{"text":"Neither shall one thrust another; they shall walk every one in his path: and when they fall upon the sword, they shall not be wounded.","ref":"Joel 2:8","synthesized":"They do not jostle one another; each proceeds in his path. They burst through the defenses, never breaking ranks.","sources":{"KJV":{"text":"Neither shall one thrust another; they shall walk every one in his path: and when they fall upon the sword, they shall not be wounded."},"BSB":{"text":"They do not jostle one another; each proceeds in his path. They burst through the defenses, never breaking ranks."}},"definableWords":["one"],"peopleInVerse":[]},"9":{"text":"They shall run to and fro in the city; they shall run upon the wall, they shall climb up upon the houses; they shall enter in at the windows like a thief.","ref":"Joel 2:9","synthesized":"They storm the city; they run along the wall; they climb into houses, entering through windows like thieves.","sources":{"KJV":{"text":"They shall run to and fro in the city; they shall run upon the wall, they shall climb up upon the houses; they shall enter in at the windows like a thief."},"BSB":{"text":"They storm the city; they run along the wall; they climb into houses, entering through windows like thieves."}},"definableWords":["run"],"peopleInVerse":[]},"10":{"text":"The earth shall quake before them; the heavens shall tremble: the sun and the moon shall be dark, and the stars shall withdraw their shining:","ref":"Joel 2:10","synthesized":"Before them the earth quakes; the heavens tremble. The sun and moon grow dark, and the stars lose their brightness.","sources":{"KJV":{"text":"The earth shall quake before them; the heavens shall tremble: the sun and the moon shall be dark, and the stars shall withdraw their shining:"},"BSB":{"text":"Before them the earth quakes; the heavens tremble. The sun and moon grow dark, and the stars lose their brightness."}},"definableWords":["earth","heavens"],"peopleInVerse":[]},"11":{"text":"And the LORD shall utter his voice before his army: for his camp is very great: for he is strong that executeth his word: for the day of the LORD is great and very terrible; and who can abide it?","ref":"Joel 2:11","synthesized":"The LORD raises His voice in the presence of His army. Indeed, His camp is very large, for mighty are those who obey His command. For the Day of the LORD is great and very dreadful. Who can endure it?","sources":{"KJV":{"text":"And the LORD shall utter his voice before his army: for his camp is very great: for he is strong that executeth his word: for the day of the LORD is great and very terrible; and who can abide it?"},"BSB":{"text":"The LORD raises His voice in the presence of His army. Indeed, His camp is very large, for mighty are those who obey His command. For the Day of the LORD is great and very dreadful. Who can endure it?"}},"definableWords":["LORD","voice","mighty","day","Lord","great"],"peopleInVerse":[]},"12":{"text":"Therefore also now, saith the LORD, turn ye even to me with all your heart, and with fasting, and with weeping, and with mourning:","ref":"Joel 2:12","synthesized":"“Yet even now,” declares the LORD, “return to Me with all your heart, with fasting, weeping, and mourning.”","sources":{"KJV":{"text":"Therefore also now, saith the LORD, turn ye even to me with all your heart, and with fasting, and with weeping, and with mourning:"},"BSB":{"text":"“Yet even now,” declares the LORD, “return to Me with all your heart, with fasting, weeping, and mourning.”"}},"definableWords":["LORD","heart"],"peopleInVerse":[]},"13":{"text":"And rend your heart, and not your garments, and turn unto the LORD your God: for he is gracious and merciful, slow to anger, and of great kindness, and repenteth him of the evil.","ref":"Joel 2:13","synthesized":"So rend your hearts and not your garments, and return to the LORD your God. For He is gracious and compassionate, slow to anger, abounding in loving devotion. And He relents from sending disaster.","sources":{"KJV":{"text":"And rend your heart, and not your garments, and turn unto the LORD your God: for he is gracious and merciful, slow to anger, and of great kindness, and repenteth him of the evil."},"BSB":{"text":"So rend your hearts and not your garments, and return to the LORD your God. For He is gracious and compassionate, slow to anger, abounding in loving devotion. And He relents from sending disaster."}},"definableWords":["LORD","God","anger"],"peopleInVerse":[]},"14":{"text":"Who knoweth if he will return and repent, and leave a blessing behind him; even a meat offering and a drink offering unto the LORD your God?","ref":"Joel 2:14","synthesized":"Who knows? He may turn and relent and leave a blessing behind Him— grain and drink offerings for the LORD your God.","sources":{"KJV":{"text":"Who knoweth if he will return and repent, and leave a blessing behind him; even a meat offering and a drink offering unto the LORD your God?"},"BSB":{"text":"Who knows? He may turn and relent and leave a blessing behind Him— grain and drink offerings for the LORD your God."}},"definableWords":["blessing","LORD","God"],"peopleInVerse":[]},"15":{"text":"Blow the trumpet in Zion, sanctify a fast, call a solemn assembly:","ref":"Joel 2:15","synthesized":"Blow the ram’s horn in Zion, consecrate a fast, proclaim a sacred assembly.","sources":{"KJV":{"text":"Blow the trumpet in Zion, sanctify a fast, call a solemn assembly:"},"BSB":{"text":"Blow the ram’s horn in Zion, consecrate a fast, proclaim a sacred assembly."}},"definableWords":["Zion","consecrate","fast"],"peopleInVerse":[]},"16":{"text":"Gather the people, sanctify the congregation, assemble the elders, gather the children, and those that suck the breasts: let the bridegroom go forth of his chamber, and the bride out of her closet.","ref":"Joel 2:16","synthesized":"Gather the people, sanctify the congregation, assemble the aged, gather the children, even those nursing at the breast. Let the bridegroom leave his room, and the bride her chamber.","sources":{"KJV":{"text":"Gather the people, sanctify the congregation, assemble the elders, gather the children, and those that suck the breasts: let the bridegroom go forth of his chamber, and the bride out of her closet."},"BSB":{"text":"Gather the people, sanctify the congregation, assemble the aged, gather the children, even those nursing at the breast. Let the bridegroom leave his room, and the bride her chamber."}},"definableWords":["people"],"peopleInVerse":[]},"17":{"text":"Let the priests, the ministers of the LORD, weep between the porch and the altar, and let them say, Spare thy people, O LORD, and give not thine heritage to reproach, that the heathen should rule over them: wherefore should they say among the people, Where is their God?","ref":"Joel 2:17","synthesized":"Let the priests who minister before the LORD weep between the portico and the altar, saying, “Spare Your people, O LORD, and do not make Your heritage a reproach, an object of scorn among the nations. Why should they say among the peoples, ‘Where is their God?’”","sources":{"KJV":{"text":"Let the priests, the ministers of the LORD, weep between the porch and the altar, and let them say, Spare thy people, O LORD, and give not thine heritage to reproach, that the heathen should rule over them: wherefore should they say among the people, Where is their God?"},"BSB":{"text":"Let the priests who minister before the LORD weep between the portico and the altar, saying, “Spare Your people, O LORD, and do not make Your heritage a reproach, an object of scorn among the nations. Why should they say among the peoples, ‘Where is their God?’”"}},"definableWords":["LORD","altar","people","Lord","make","nations","God"],"peopleInVerse":[]},"18":{"text":"Then will the LORD be jealous for his land, and pity his people.","ref":"Joel 2:18","synthesized":"Then the LORD became jealous for His land, and He spared His people.","sources":{"KJV":{"text":"Then will the LORD be jealous for his land, and pity his people."},"BSB":{"text":"Then the LORD became jealous for His land, and He spared His people."}},"definableWords":["LORD","land","people"],"peopleInVerse":[]},"19":{"text":"Yea, the LORD will answer and say unto his people, Behold, I will send you corn, and wine, and oil, and ye shall be satisfied therewith: and I will no more make you a reproach among the heathen:","ref":"Joel 2:19","synthesized":"And the LORD answered His people:   “Behold, I will send you grain, new wine, and oil, and by them you will be satisfied. I will never again make you a reproach among the nations.","sources":{"KJV":{"text":"Yea, the LORD will answer and say unto his people, Behold, I will send you corn, and wine, and oil, and ye shall be satisfied therewith: and I will no more make you a reproach among the heathen:"},"BSB":{"text":"And the LORD answered His people:   “Behold, I will send you grain, new wine, and oil, and by them you will be satisfied. I will never again make you a reproach among the nations."}},"definableWords":["LORD","people","make","nations"],"peopleInVerse":[]},"20":{"text":"But I will remove far off from you the northern army, and will drive him into a land barren and desolate, with his face toward the east sea, and his hinder part toward the utmost sea, and his stink shall come up, and his ill savour shall come up, because he hath done great things.","ref":"Joel 2:20","synthesized":"The northern army I will drive away from you, banishing it to a barren and desolate land, its front ranks into the Eastern Sea, and its rear guard into the Western Sea. And its stench will rise; its foul odor will ascend.   For He has done great things.","sources":{"KJV":{"text":"But I will remove far off from you the northern army, and will drive him into a land barren and desolate, with his face toward the east sea, and his hinder part toward the utmost sea, and his stink shall come up, and his ill savour shall come up, because he hath done great things."},"BSB":{"text":"The northern army I will drive away from you, banishing it to a barren and desolate land, its front ranks into the Eastern Sea, and its rear guard into the Western Sea. And its stench will rise; its foul odor will ascend.   For He has done great things."}},"definableWords":["land","sea","great"],"peopleInVerse":[]},"21":{"text":"Fear not, O land; be glad and rejoice: for the LORD will do great things.","ref":"Joel 2:21","synthesized":"Do not be afraid, O land; rejoice and be glad, for the LORD has done great things.","sources":{"KJV":{"text":"Fear not, O land; be glad and rejoice: for the LORD will do great things."},"BSB":{"text":"Do not be afraid, O land; rejoice and be glad, for the LORD has done great things."}},"definableWords":["land","LORD","great"],"peopleInVerse":[]},"22":{"text":"Be not afraid, ye beasts of the field: for the pastures of the wilderness do spring, for the tree beareth her fruit, the fig tree and the vine do yield their strength.","ref":"Joel 2:22","synthesized":"Do not be afraid, O beasts of the field, for the open pastures have turned green, the trees bear their fruit, and the fig tree and vine yield their best.","sources":{"KJV":{"text":"Be not afraid, ye beasts of the field: for the pastures of the wilderness do spring, for the tree beareth her fruit, the fig tree and the vine do yield their strength."},"BSB":{"text":"Do not be afraid, O beasts of the field, for the open pastures have turned green, the trees bear their fruit, and the fig tree and vine yield their best."}},"definableWords":["field","trees","tree"],"peopleInVerse":[]},"23":{"text":"Be glad then, ye children of Zion, and rejoice in the LORD your God: for he hath given you the former rain moderately, and he will cause to come down for you the rain, the former rain, and the latter rain in the first month.","ref":"Joel 2:23","synthesized":"Be glad, O children of Zion, and rejoice in the LORD your God, for He has given you the autumn rains for your vindication. He sends you showers, both autumn and spring rains, as before.","sources":{"KJV":{"text":"Be glad then, ye children of Zion, and rejoice in the LORD your God: for he hath given you the former rain moderately, and he will cause to come down for you the rain, the former rain, and the latter rain in the first month."},"BSB":{"text":"Be glad, O children of Zion, and rejoice in the LORD your God, for He has given you the autumn rains for your vindication. He sends you showers, both autumn and spring rains, as before."}},"definableWords":["Zion","LORD","God"],"peopleInVerse":[]},"24":{"text":"And the floors shall be full of wheat, and the vats shall overflow with wine and oil.","ref":"Joel 2:24","synthesized":"The threshing floors will be full of grain, and the vats will overflow with new wine and oil.","sources":{"KJV":{"text":"And the floors shall be full of wheat, and the vats shall overflow with wine and oil."},"BSB":{"text":"The threshing floors will be full of grain, and the vats will overflow with new wine and oil."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And I will restore to you the years that the locust hath eaten, the cankerworm, and the caterpiller, and the palmerworm, my great army which I sent among you.","ref":"Joel 2:25","synthesized":"I will repay you for the years eaten by locusts— the swarming locust, the young locust, the destroying locust, and the devouring locust— My great army that I sent against you.","sources":{"KJV":{"text":"And I will restore to you the years that the locust hath eaten, the cankerworm, and the caterpiller, and the palmerworm, my great army which I sent among you."},"BSB":{"text":"I will repay you for the years eaten by locusts— the swarming locust, the young locust, the destroying locust, and the devouring locust— My great army that I sent against you."}},"definableWords":["years","great"],"peopleInVerse":[]},"26":{"text":"And ye shall eat in plenty, and be satisfied, and praise the name of the LORD your God, that hath dealt wondrously with you: and my people shall never be ashamed.","ref":"Joel 2:26","synthesized":"You will have plenty to eat, until you are satisfied. You will praise the name of the LORD your God, who has worked wonders for you. My people will never again be put to shame.","sources":{"KJV":{"text":"And ye shall eat in plenty, and be satisfied, and praise the name of the LORD your God, that hath dealt wondrously with you: and my people shall never be ashamed."},"BSB":{"text":"You will have plenty to eat, until you are satisfied. You will praise the name of the LORD your God, who has worked wonders for you. My people will never again be put to shame."}},"definableWords":["praise","name","LORD","God","people"],"peopleInVerse":[]},"27":{"text":"And ye shall know that I am in the midst of Israel, and that I am the LORD your God, and none else: and my people shall never be ashamed.","ref":"Joel 2:27","synthesized":"Then you will know that I am present in Israel and that I am the LORD your God, and there is no other. My people will never again be put to shame.","sources":{"KJV":{"text":"And ye shall know that I am in the midst of Israel, and that I am the LORD your God, and none else: and my people shall never be ashamed."},"BSB":{"text":"Then you will know that I am present in Israel and that I am the LORD your God, and there is no other. My people will never again be put to shame."}},"definableWords":["Israel","LORD","God","people"],"peopleInVerse":[]},"28":{"text":"And it shall come to pass afterward, that I will pour out my spirit upon all flesh; and your sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions:","ref":"Joel 2:28","synthesized":"And afterward, I will pour out My Spirit on all people. Your sons and daughters will prophesy, your old men will dream dreams, your young men will see visions.","sources":{"KJV":{"text":"And it shall come to pass afterward, that I will pour out my spirit upon all flesh; and your sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions:"},"BSB":{"text":"And afterward, I will pour out My Spirit on all people. Your sons and daughters will prophesy, your old men will dream dreams, your young men will see visions."}},"definableWords":["Spirit","people","sons","daughters","men","see"],"peopleInVerse":[]},"29":{"text":"And also upon the servants and upon the handmaids in those days will I pour out my spirit.","ref":"Joel 2:29","synthesized":"Even on My menservants and maidservants, I will pour out My Spirit in those days.","sources":{"KJV":{"text":"And also upon the servants and upon the handmaids in those days will I pour out my spirit."},"BSB":{"text":"Even on My menservants and maidservants, I will pour out My Spirit in those days."}},"definableWords":["Spirit","days"],"peopleInVerse":[]},"30":{"text":"And I will shew wonders in the heavens and in the earth, blood, and fire, and pillars of smoke.","ref":"Joel 2:30","synthesized":"I will show wonders in the heavens and on the earth, blood and fire and columns of smoke.","sources":{"KJV":{"text":"And I will shew wonders in the heavens and in the earth, blood, and fire, and pillars of smoke."},"BSB":{"text":"I will show wonders in the heavens and on the earth, blood and fire and columns of smoke."}},"definableWords":["heavens","earth","blood"],"peopleInVerse":[]},"31":{"text":"The sun shall be turned into darkness, and the moon into blood, before the great and the terrible day of the LORD come.","ref":"Joel 2:31","synthesized":"The sun will be turned to darkness and the moon to blood before the coming of the great and awesome Day of the LORD.","sources":{"KJV":{"text":"The sun shall be turned into darkness, and the moon into blood, before the great and the terrible day of the LORD come."},"BSB":{"text":"The sun will be turned to darkness and the moon to blood before the coming of the great and awesome Day of the LORD."}},"definableWords":["darkness","blood","great","day","LORD"],"peopleInVerse":[]},"32":{"text":"And it shall come to pass, that whosoever shall call on the name of the LORD shall be delivered: for in mount Zion and in Jerusalem shall be deliverance, as the LORD hath said, and in the remnant whom the LORD shall call.","ref":"Joel 2:32","synthesized":"And everyone who calls on the name of the LORD will be saved; for on Mount Zion and in Jerusalem there will be deliverance, as the LORD has promised, among the remnant called by the LORD.","sources":{"KJV":{"text":"And it shall come to pass, that whosoever shall call on the name of the LORD shall be delivered: for in mount Zion and in Jerusalem shall be deliverance, as the LORD hath said, and in the remnant whom the LORD shall call."},"BSB":{"text":"And everyone who calls on the name of the LORD will be saved; for on Mount Zion and in Jerusalem there will be deliverance, as the LORD has promised, among the remnant called by the LORD."}},"definableWords":["name","LORD","Zion","Jerusalem","Lord","remnant"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"THE VALLEY OF DECISION","verses":{"1":{"text":"For, behold, in those days, and in that time, when I shall bring again the captivity of Judah and Jerusalem,","ref":"Joel 3:1","synthesized":"“Yes, in those days and at that time, when I restore Judah and Jerusalem from captivity,","sources":{"KJV":{"text":"For, behold, in those days, and in that time, when I shall bring again the captivity of Judah and Jerusalem,"},"BSB":{"text":"“Yes, in those days and at that time, when I restore Judah and Jerusalem from captivity,"}},"definableWords":["days","Judah","Jerusalem"],"peopleInVerse":[]},"2":{"text":"I will also gather all nations, and will bring them down into the valley of Jehoshaphat, and will plead with them there for my people and for my heritage Israel, whom they have scattered among the nations, and parted my land.","ref":"Joel 3:2","synthesized":"I will gather all the nations and bring them down to the Valley of Jehoshaphat. There I will enter into judgment against them concerning My people, My inheritance, Israel, whom they have scattered among the nations as they divided up My land.","sources":{"KJV":{"text":"I will also gather all nations, and will bring them down into the valley of Jehoshaphat, and will plead with them there for my people and for my heritage Israel, whom they have scattered among the nations, and parted my land."},"BSB":{"text":"I will gather all the nations and bring them down to the Valley of Jehoshaphat. There I will enter into judgment against them concerning My people, My inheritance, Israel, whom they have scattered among the nations as they divided up My land."}},"definableWords":["nations","judgment","people","Israel","land"],"peopleInVerse":[]},"3":{"text":"And they have cast lots for my people; and have given a boy for an harlot, and sold a girl for wine, that they might drink.","ref":"Joel 3:3","synthesized":"They cast lots for My people; they bartered a boy for a prostitute and sold a girl for wine to drink.","sources":{"KJV":{"text":"And they have cast lots for my people; and have given a boy for an harlot, and sold a girl for wine, that they might drink."},"BSB":{"text":"They cast lots for My people; they bartered a boy for a prostitute and sold a girl for wine to drink."}},"definableWords":["people"],"peopleInVerse":[]},"4":{"text":"Yea, and what have ye to do with me, O Tyre, and Zidon, and all the coasts of Palestine? will ye render me a recompence? and if ye recompense me, swiftly and speedily will I return your recompence upon your own head;","ref":"Joel 3:4","synthesized":"Now what do you have against Me, O Tyre, Sidon, and all the regions of Philistia? Are you rendering against Me a recompense? If you retaliate against Me, I will swiftly and speedily return your recompense upon your heads.","sources":{"KJV":{"text":"Yea, and what have ye to do with me, O Tyre, and Zidon, and all the coasts of Palestine? will ye render me a recompence? and if ye recompense me, swiftly and speedily will I return your recompence upon your own head;"},"BSB":{"text":"Now what do you have against Me, O Tyre, Sidon, and all the regions of Philistia? Are you rendering against Me a recompense? If you retaliate against Me, I will swiftly and speedily return your recompense upon your heads."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Because ye have taken my silver and my gold, and have carried into your temples my goodly pleasant things:","ref":"Joel 3:5","synthesized":"For you took My silver and gold and carried off My finest treasures to your temples.","sources":{"KJV":{"text":"Because ye have taken my silver and my gold, and have carried into your temples my goodly pleasant things:"},"BSB":{"text":"For you took My silver and gold and carried off My finest treasures to your temples."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"The children also of Judah and the children of Jerusalem have ye sold unto the Grecians, that ye might remove them far from their border.","ref":"Joel 3:6","synthesized":"You sold the people of Judah and Jerusalem to the Greeks, to send them far from their homeland.","sources":{"KJV":{"text":"The children also of Judah and the children of Jerusalem have ye sold unto the Grecians, that ye might remove them far from their border."},"BSB":{"text":"You sold the people of Judah and Jerusalem to the Greeks, to send them far from their homeland."}},"definableWords":["people","Judah","Jerusalem"],"peopleInVerse":[]},"7":{"text":"Behold, I will raise them out of the place whither ye have sold them, and will return your recompence upon your own head:","ref":"Joel 3:7","synthesized":"Behold, I will rouse them from the places to which you sold them; I will return your recompense upon your heads.","sources":{"KJV":{"text":"Behold, I will raise them out of the place whither ye have sold them, and will return your recompence upon your own head:"},"BSB":{"text":"Behold, I will rouse them from the places to which you sold them; I will return your recompense upon your heads."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"And I will sell your sons and your daughters into the hand of the children of Judah, and they shall sell them to the Sabeans, to a people far off: for the LORD hath spoken it.","ref":"Joel 3:8","synthesized":"I will sell your sons and daughters into the hands of the people of Judah, and they will sell them to the Sabeans—to a distant nation.”  Indeed, the LORD has spoken.","sources":{"KJV":{"text":"And I will sell your sons and your daughters into the hand of the children of Judah, and they shall sell them to the Sabeans, to a people far off: for the LORD hath spoken it."},"BSB":{"text":"I will sell your sons and daughters into the hands of the people of Judah, and they will sell them to the Sabeans—to a distant nation.”  Indeed, the LORD has spoken."}},"definableWords":["sons","daughters","people","Judah","nation","LORD"],"peopleInVerse":[]},"9":{"text":"Proclaim ye this among the Gentiles; Prepare war, wake up the mighty men, let all the men of war draw near; let them come up:","ref":"Joel 3:9","synthesized":"Proclaim this among the nations:  “Prepare for war; rouse the mighty men; let all the men of war advance and attack!","sources":{"KJV":{"text":"Proclaim ye this among the Gentiles; Prepare war, wake up the mighty men, let all the men of war draw near; let them come up:"},"BSB":{"text":"Proclaim this among the nations:  “Prepare for war; rouse the mighty men; let all the men of war advance and attack!"}},"definableWords":["nations","mighty","men"],"peopleInVerse":[]},"10":{"text":"Beat your plowshares into swords, and your pruninghooks into spears: let the weak say, I am strong.","ref":"Joel 3:10","synthesized":"Beat your plowshares into swords and your pruning hooks into spears. Let the weak say, ‘I am strong!’","sources":{"KJV":{"text":"Beat your plowshares into swords, and your pruninghooks into spears: let the weak say, I am strong."},"BSB":{"text":"Beat your plowshares into swords and your pruning hooks into spears. Let the weak say, ‘I am strong!’"}},"definableWords":["strong"],"peopleInVerse":[]},"11":{"text":"Assemble yourselves, and come, all ye heathen, and gather yourselves together round about: thither cause thy mighty ones to come down, O LORD.","ref":"Joel 3:11","synthesized":"Come quickly, all you surrounding nations, and gather yourselves. Bring down Your mighty ones, O LORD.","sources":{"KJV":{"text":"Assemble yourselves, and come, all ye heathen, and gather yourselves together round about: thither cause thy mighty ones to come down, O LORD."},"BSB":{"text":"Come quickly, all you surrounding nations, and gather yourselves. Bring down Your mighty ones, O LORD."}},"definableWords":["nations","mighty","LORD"],"peopleInVerse":[]},"12":{"text":"Let the heathen be wakened, and come up to the valley of Jehoshaphat: for there will I sit to judge all the heathen round about.","ref":"Joel 3:12","synthesized":"Let the nations be roused and advance to the Valley of Jehoshaphat, for there I will sit down to judge all the nations on every side.","sources":{"KJV":{"text":"Let the heathen be wakened, and come up to the valley of Jehoshaphat: for there will I sit to judge all the heathen round about."},"BSB":{"text":"Let the nations be roused and advance to the Valley of Jehoshaphat, for there I will sit down to judge all the nations on every side."}},"definableWords":["nations"],"peopleInVerse":[]},"13":{"text":"Put ye in the sickle, for the harvest is ripe: come, get you down; for the press is full, the fats overflow; for their wickedness is great.","ref":"Joel 3:13","synthesized":"Swing the sickle, for the harvest is ripe. Come, trample the grapes, for the winepress is full; the wine vats overflow because their wickedness is great.","sources":{"KJV":{"text":"Put ye in the sickle, for the harvest is ripe: come, get you down; for the press is full, the fats overflow; for their wickedness is great."},"BSB":{"text":"Swing the sickle, for the harvest is ripe. Come, trample the grapes, for the winepress is full; the wine vats overflow because their wickedness is great."}},"definableWords":["great"],"peopleInVerse":[]},"14":{"text":"Multitudes, multitudes in the valley of decision: for the day of the LORD is near in the valley of decision.","ref":"Joel 3:14","synthesized":"Multitudes, multitudes in the valley of decision! For the Day of the LORD is near in the valley of decision.","sources":{"KJV":{"text":"Multitudes, multitudes in the valley of decision: for the day of the LORD is near in the valley of decision."},"BSB":{"text":"Multitudes, multitudes in the valley of decision! For the Day of the LORD is near in the valley of decision."}},"definableWords":["day","LORD"],"peopleInVerse":[]},"15":{"text":"The sun and the moon shall be darkened, and the stars shall withdraw their shining.","ref":"Joel 3:15","synthesized":"The sun and moon will grow dark, and the stars will no longer shine.","sources":{"KJV":{"text":"The sun and the moon shall be darkened, and the stars shall withdraw their shining."},"BSB":{"text":"The sun and moon will grow dark, and the stars will no longer shine."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"The LORD also shall roar out of Zion, and utter his voice from Jerusalem; and the heavens and the earth shall shake: but the LORD will be the hope of his people, and the strength of the children of Israel.","ref":"Joel 3:16","synthesized":"The LORD will roar from Zion and raise His voice from Jerusalem; heaven and earth will tremble. But the LORD will be a refuge for His people, a stronghold for the people of Israel.","sources":{"KJV":{"text":"The LORD also shall roar out of Zion, and utter his voice from Jerusalem; and the heavens and the earth shall shake: but the LORD will be the hope of his people, and the strength of the children of Israel."},"BSB":{"text":"The LORD will roar from Zion and raise His voice from Jerusalem; heaven and earth will tremble. But the LORD will be a refuge for His people, a stronghold for the people of Israel."}},"definableWords":["LORD","Zion","voice","Jerusalem","heaven","earth","Lord","people","Israel"],"peopleInVerse":[]},"17":{"text":"So shall ye know that I am the LORD your God dwelling in Zion, my holy mountain: then shall Jerusalem be holy, and there shall no strangers pass through her any more.","ref":"Joel 3:17","synthesized":"Then you will know that I am the LORD your God, who dwells in Zion, My holy mountain. Jerusalem will be holy, never again to be overrun by foreigners.","sources":{"KJV":{"text":"So shall ye know that I am the LORD your God dwelling in Zion, my holy mountain: then shall Jerusalem be holy, and there shall no strangers pass through her any more."},"BSB":{"text":"Then you will know that I am the LORD your God, who dwells in Zion, My holy mountain. Jerusalem will be holy, never again to be overrun by foreigners."}},"definableWords":["LORD","God","Zion","holy","Jerusalem"],"peopleInVerse":[]},"18":{"text":"And it shall come to pass in that day, that the mountains shall drop down new wine, and the hills shall flow with milk, and all the rivers of Judah shall flow with waters, and a fountain shall come forth of the house of the LORD, and shall water the valley of Shittim.","ref":"Joel 3:18","synthesized":"And in that day the mountains will drip with sweet wine, and the hills will flow with milk. All the streams of Judah will run with water, and a spring will flow from the house of the LORD to water the Valley of Acacias.","sources":{"KJV":{"text":"And it shall come to pass in that day, that the mountains shall drop down new wine, and the hills shall flow with milk, and all the rivers of Judah shall flow with waters, and a fountain shall come forth of the house of the LORD, and shall water the valley of Shittim."},"BSB":{"text":"And in that day the mountains will drip with sweet wine, and the hills will flow with milk. All the streams of Judah will run with water, and a spring will flow from the house of the LORD to water the Valley of Acacias."}},"definableWords":["day","Judah","run","water","house","LORD"],"peopleInVerse":[]},"19":{"text":"Egypt shall be a desolation, and Edom shall be a desolate wilderness, for the violence against the children of Judah, because they have shed innocent blood in their land.","ref":"Joel 3:19","synthesized":"Egypt will become desolate, and Edom a desert wasteland, because of the violence done to the people of Judah, in whose land they shed innocent blood.","sources":{"KJV":{"text":"Egypt shall be a desolation, and Edom shall be a desolate wilderness, for the violence against the children of Judah, because they have shed innocent blood in their land."},"BSB":{"text":"Egypt will become desolate, and Edom a desert wasteland, because of the violence done to the people of Judah, in whose land they shed innocent blood."}},"definableWords":["Egypt","Edom","people","Judah","land","blood"],"peopleInVerse":[]},"20":{"text":"But Judah shall dwell for ever, and Jerusalem from generation to generation.","ref":"Joel 3:20","synthesized":"But Judah will be inhabited forever, and Jerusalem from generation to generation.","sources":{"KJV":{"text":"But Judah shall dwell for ever, and Jerusalem from generation to generation."},"BSB":{"text":"But Judah will be inhabited forever, and Jerusalem from generation to generation."}},"definableWords":["Judah","Jerusalem"],"peopleInVerse":[]},"21":{"text":"For I will cleanse their blood that I have not cleansed: for the LORD dwelleth in Zion.","ref":"Joel 3:21","synthesized":"For I will avenge their blood, which I have not yet avenged.” For the LORD dwells in Zion.","sources":{"KJV":{"text":"For I will cleanse their blood that I have not cleansed: for the LORD dwelleth in Zion."},"BSB":{"text":"For I will avenge their blood, which I have not yet avenged.” For the LORD dwells in Zion."}},"definableWords":["blood","LORD","Zion"],"peopleInVerse":[]}}}};